            { type: "book", title: "Wren & Martin — High School English Grammar and Composition", author: "Wren & Martin (rev. N.D.V. Prasada Rao)", chapter: "Composition — Paragraph-Writing", note: "This writing skill is covered in Wren & Martin's Composition section, 'Composition — Paragraph-Writing'.", url: "https://openlibrary.org/search?q=wren+martin+high+school+english+grammar+and+composition" },
            { type: "book", enrichment: true, title: "On Writing: A Memoir of the Craft", author: "Stephen King", chapter: "(the 'Toolbox' and 'On Writing' craft sections)", note: "Enrichment read (advanced / with guidance): a celebrated author's practical advice on storytelling and the craft of writing.", url: "https://archive.org/details/onwritingmemoiro0000king" }
